using ArgParams = struct { unsigned int vecwidth; };

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; argc > i; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

// CUDA Kernel for bench_block logic (8-wide version)
template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_block_kernel_8(Element* data, Element* sum_ptr, size_t total_len) {
  size_t base_idx = blockIdx.x * static_chunk_size + threadIdx.x * 8;
  if (base_idx >= total_len) return;

  Element f[8];
  for(int k=0; k<8; ++k) {
      if (base_idx + k < total_len) f[k] = data[base_idx + k];
      else f[k] = 0;
  }

  Element t[8];
  for(int k=0; k<8; ++k) t[k] = f[k];

  size_t full_iters = compute_iterations / 8;
  for (size_t j = 0; j < full_iters; j++) {
    t[0] = t[0] * t[0] + f[0];
    t[1] = t[1] * t[1] + f[1];
    t[2] = t[2] * t[2] + f[2];
    t[3] = t[3] * t[3] + f[3];
    t[4] = t[4] * t[4] + f[4];
    t[5] = t[5] * t[5] + f[5];
    t[6] = t[6] * t[6] + f[6];
    t[7] = t[7] * t[7] + f[7];
  }

  size_t rem = compute_iterations % 8;
  if (rem > 0) t[0] = t[0] * t[0] + f[0];
  if (rem > 1) t[1] = t[1] * t[1] + f[1];
  if (rem > 2) t[2] = t[2] * t[2] + f[2];
  if (rem > 3) t[3] = t[3] * t[3] + f[3];
  if (rem > 4) t[4] = t[4] * t[4] + f[4];
  if (rem > 5) t[5] = t[5] * t[5] + f[5];
  if (rem > 6) t[6] = t[6] * t[6] + f[6];

  Element block_sum = t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];

  __shared__ Element shared_data[static_chunk_size];
  shared_data[threadIdx.x] = block_sum;
  __syncthreads();

  if (static_chunk_size >= 1024) { if (threadIdx.x < 512) shared_data[threadIdx.x] += shared_data[threadIdx.x + 512]; __syncthreads(); }
  if (static_chunk_size >= 512) { if (threadIdx.x < 256) shared_data[threadIdx.x] += shared_data[threadIdx.x + 256]; __syncthreads(); }
  if (static_chunk_size >= 256) { if (threadIdx.x < 128) shared_data[threadIdx.x] += shared_data[threadIdx.x + 128]; __syncthreads(); }
  if (static_chunk_size >= 128) { if (threadIdx.x < 64) shared_data[threadIdx.x] += shared_data[threadIdx.x + 64]; __syncthreads(); }
  if (threadIdx.x < 32) {
    volatile Element* vsm = shared_data;
    vsm[threadIdx.x] += vsm[threadIdx.x + 32];
    vsm[threadIdx.x] += vsm[threadIdx.x + 16];
    vsm[threadIdx.x] += vsm[threadIdx.x + 8];
    vsm[threadIdx.x] += vsm[threadIdx.x + 4];
    vsm[threadIdx.x] += vsm[threadIdx.x + 2];
    vsm[threadIdx.x] += vsm[threadIdx.x + 1];
  }

  if (threadIdx.x == 0) {
    atomicAdd(sum_ptr, shared_data[0]);
  }
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src_dev, Element* sum_dev) {
  constexpr size_t static_chunk_size = 4096;
  // Reset sum
  Element zero = 0;
  cudaMemcpy(sum_dev, &zero, sizeof(Element), cudaMemcpyHostToDevice);

  int threads_per_block = static_chunk_size;
  int blocks = (len + static_chunk_size - 1) / static_chunk_size;

  // Launch kernel
  bench_block_kernel_8<Element, compute_iterations, static_chunk_size>(blocks, threads_per_block, src_dev, sum_dev, len);

  cudaDeviceSynchronize();

  Element result;
  cudaMemcpy(&result, sum_dev, sizeof(Element), cudaMemcpyDeviceToHost);

  *src_dev = result; // Mimic *src = sum
  return len;
}

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);
  auto x_2 = std::chrono::steady_clock::now();

  double* ptr_dev;
  cudaMalloc(&ptr_dev, size);

  std::vector<double> init_data(num_elements);
  init_data[0] = 1.0;
  init_data[1] = -1.0;
  for(size_t i=2; i<num_elements; ++i) init_data[i] = 1.0; // dummy

  cudaMemcpy(ptr_dev, init_data.data(), size, cudaMemcpyHostToDevice);

  double* sum_dev;
  cudaMalloc(&sum_dev, sizeof(double));

  bench_cuda<double, 16>(num_elements, 1., -1., ptr_dev, sum_dev);

  auto var_0 = std::chrono::steady_clock::now() - x_2;

  cudaFree(ptr_dev);
  cudaFree(sum_dev);

  return std::chrono::duration_cast<std::chrono::microseconds>(var_0).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = std::chrono::steady_clock::now();
  op();
  auto timer_duration = std::chrono::steady_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

// Get CUDA max threads (approximation of concurrency for benchmark params)
int get_cuda_max_threads() {
  int device;
  cudaGetDevice(&device);
  cudaDeviceProp prop;
  cudaGetDeviceProperties(&prop, device);
  return prop.multiProcessorCount * 1024; // Approximate concurrency
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; total_runs > i; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t v_1, int compute_iterations)
      : memory_space_{v_1}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

// Explicit specialization to avoid recursive template expansion issues with variadic templates in CUDA
template <unsigned int compute_iterations>
void runbench_single(void* c_host, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  // Allocate GPU memory
  float *c_as_float_dev;
  cudaMalloc(&c_as_float_dev, cs.element_count<float>() * sizeof(float));

  // Initialize data on GPU
  std::vector<float> init_f(cs.element_count<float>(), 1.0f);
  if (init_f.size() > 1) init_f[1] = -1.0f;
  cudaMemcpy(c_as_float_dev, init_f.data(), cs.element_count<float>() * sizeof(float), cudaMemcpyHostToDevice);

  float *sum_f_dev;
  cudaMalloc(&sum_f_dev, sizeof(float));

  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, c_as_float_dev, sum_f_dev);
    });
  });

  double *c_as_double_dev;
  cudaMalloc(&c_as_double_dev, cs.element_count<double>() * sizeof(double));
  std::vector<double> init_d(cs.element_count<double>(), 1.0);
  if (init_d.size() > 1) init_d[1] = -1.0;
  cudaMemcpy(c_as_double_dev, init_d.data(), cs.element_count<double>() * sizeof(double), cudaMemcpyHostToDevice);

  double *sum_d_dev;
  cudaMalloc(&sum_d_dev, sizeof(double));

  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<double, compute_iterations>(cs.element_count<double>(), 1., -1., c_as_double_dev, sum_d_dev);
    });
  });

  int *c_as_int_dev;
  cudaMalloc(&c_as_int_dev, cs.element_count<int>() * sizeof(int));
  std::vector<int> init_i(cs.element_count<int>(), 1);
  if (init_i.size() > 1) init_i[1] = -1;
  cudaMemcpy(c_as_int_dev, init_i.data(), cs.element_count<int>() * sizeof(int), cudaMemcpyHostToDevice);

  int *sum_i_dev;
  cudaMalloc(&sum_i_dev, sizeof(int));

  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int_dev, sum_i_dev);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;

  cudaFree(c_as_float_dev); cudaFree(sum_f_dev);
  cudaFree(c_as_double_dev); cudaFree(sum_d_dev);
  cudaFree(c_as_int_dev); cudaFree(sum_i_dev);
}

