void mixbenchGPU(double* c_host, long size) {
  // In CUDA version, 'c_host' is host memory used for initialization or reference, 
  // but the actual work is on GPU. 
  // The original CPU code zeroes the array. We'll do it on host for compatibility.
  int* c_as_int = (int*)c_host;
  size_t count = size / sizeof(int);
  for(size_t i=0; i<count; ++i) c_as_int[i] = 0;

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(c_host, size);

  runbench_range(c_host, size);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;
}

int main(int argc, char* argv[]) {
  std::cout << "mixbench (" << VERSION_INFO << ")" << std::endl;

  // Use CUDA device properties to determine "concurrency" equivalent
  int hardware_concurrency = get_cuda_max_threads();

  ArgParams args{static_cast<unsigned int>(
      hardware_concurrency * DEF_VECTOR_SIZE_PER_THREAD / (1024 * 1024))};

  if (!argument_parsing(argc, argv, &args)) {
    std::cout << "Usage: mixbench [options] [array size(1024^2)]"
              << std::endl
              << std::endl
              << "Options:" << std::endl
              << "  -h or --help              Show this message" << std::endl;

    exit(1);
  }

  std::cout << "Use \"-h\" argument to see available options" << std::endl;

  const size_t VEC_WIDTH = 1024 * 1024 * args.vecwidth;

  std::unique_ptr<std::byte[]> c;
  c.reset(new (std::align_val_t(64)) std::byte[VEC_WIDTH * sizeof(double)]);

  std::cout << "Working memory size: " << args.vecwidth * sizeof(double) << "MB"
            << std::endl;
  std::cout << "Total threads (equiv): " << hardware_concurrency << std::endl;

  // Initialize CUDA
  cudaSetDevice(0);
  StoreDeviceInfo(stdout);

  size_t freeCUDAMem, totalCUDAMem;
  cudaMemGetInfo(&freeCUDAMem, &totalCUDAMem);
  printf("Total GPU memory %lu, free %lu\n", totalCUDAMem, freeCUDAMem);
  printf("Buffer size:          %dMB\n", (int)(VEC_WIDTH * sizeof(double) / (1024 * 1024)));

  mixbenchGPU((double*)c.get(), VEC_WIDTH * sizeof(double));

  return 0;
}
